import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import "./index.css";
import { AuthProvider, useAuth } from "./context/AuthContext"; // Added Auth Provider context hooks
import HeroPage from "./components/HeroPage";                  // Added Step 3 Hero landing component
import { useTasks } from "./hooks/useTasks";
import StatsBar from "./components/StatsBar";
import FilterTabs from "./components/FilterTabs";
import TaskList from "./components/TaskList";
import TaskForm from "./components/TaskForm";
import ConfirmDialog from "./components/ConfirmDialog";
import Modal from "./components/Modal";

function App() {
  const { user, logoutUser } = useAuth(); // Read current session data and handlers from state
  const { tasks, loading, error, addTask, editTask, removeTask } = useTasks();
  const [filter,     setFilter]     = useState("all");
  const [showCreate, setShowCreate] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [deleteId,   setDeleteId]   = useState(null);

  // 🛡️ STEP 4 ROUTING REDIRECT: Kick out unauthenticated visitors straight to the Landing/Auth UI
  if (!user) {
    return <HeroPage />;
  }

  const filtered = filter === "all"
    ? tasks
    : tasks.filter(t => t.status === filter);

  const handleCreate = async (form) => {
    await addTask(form);
    setShowCreate(false);
  };

  const handleEdit = async (form) => {
    await editTask(editTarget._id, form);
    setEditTarget(null);
  };

  const handleDelete = async () => {
    await removeTask(deleteId);
    setDeleteId(null);
  };

  return (
    <div className="min-h-screen bg-gray-50">

      {/* 👤 NEW RESPONSIVE USER PROFILE NAVIGATION HEADER BAR */}
      <nav className="bg-white border-b border-gray-100 px-4 sm:px-6 lg:px-8 py-3.5 shadow-sm">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            {/* Round custom visual initials avatar container */}
            <div className="h-9 w-9 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold text-sm shadow-inner uppercase">
              {user.name ? user.name.charAt(0) : "U"}
            </div>
            <div>
              <p className="text-[10px] text-gray-400 uppercase tracking-wider font-semibold leading-none">Logged in as</p>
              <h4 className="text-sm font-semibold text-gray-800 mt-0.5">{user.name}</h4>
            </div>
          </div>

          <button
            onClick={logoutUser}
            className="text-xs font-semibold text-gray-500 hover:text-red-500 border border-gray-200 hover:border-red-200 px-3 py-1.5 rounded-xl bg-gray-50 hover:bg-red-50 transition-colors"
          >
            Logout 🚪
          </button>
        </div>
      </nav>

      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-6 sm:py-8">

        {/* Workspace Title Header */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 tracking-tight">Task Manager</h1>
            <p className="text-sm text-gray-500 mt-0.5">Welcome back, {user.name} • {tasks.length} tasks total</p>
          </div>
          <button
            onClick={() => setShowCreate(true)}
            className="w-full sm:w-auto flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium px-4 py-2.5 sm:py-2 rounded-xl transition-colors shadow-sm"
          >
            <span className="text-lg leading-none">+</span> New Task
          </button>
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-600 text-sm px-4 py-3 rounded-xl mb-6">
            {error}
          </div>
        )}

        {loading ? (
          <div className="text-center py-20 text-gray-400 text-sm">Loading tasks...</div>
        ) : (
          <>
            <StatsBar tasks={tasks} />
            <FilterTabs filter={filter} setFilter={setFilter} tasks={tasks} />

            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
              <TaskList
                tasks={filtered}
                onEdit={setEditTarget}
                onDelete={setDeleteId}
              />
            </div>
          </>
        )}
      </div>

      {showCreate && (
        <Modal title="Create New Task" onClose={() => setShowCreate(false)}>
          <TaskForm onSubmit={handleCreate} onCancel={() => setShowCreate(false)} />
        </Modal>
      )}

      {editTarget && (
        <Modal title="Edit Task" onClose={() => setEditTarget(null)}>
          <TaskForm initial={editTarget} onSubmit={handleEdit} onCancel={() => setEditTarget(null)} />
        </Modal>
      )}

      {/* Delete Confirm */}
      {deleteId && (
        <ConfirmDialog
          message="Are you sure you want to delete this task? This action cannot be undone."
          onConfirm={handleDelete}
          onCancel={() => setDeleteId(null)}
        />
      )}
    </div>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <AuthProvider>
      <App />
    </AuthProvider>
  </React.StrictMode>
);
